const merged = {};

for (const item of $input.all()) {
  Object.assign(merged, item.json.output || {});
}

return [
  {
    json: { ...merged }
  }
];

const stringify = JSON.stringify($input.all())

return {
  product_data: stringify
};

const chunkSize = 20;
const inputItems = $input.all();

const output = [];

for (const item of inputItems) {
  const sourceSchema = item.json.columns || {};
  const productData = item.json.product_data;
  const understanding = item.json.understanding;
  const entries = Object.entries(sourceSchema);

  for (let i = 0; i < entries.length; i += chunkSize) {
    const chunk = entries.slice(i, i + chunkSize);

    const properties = Object.fromEntries(chunk);
    const required = chunk.map(([key]) => key);

    output.push({
      json: {
        schema: {
          type: "object",
          properties,
          // required,
          // additionalProperties: false,
        },
        product_data: productData,
        understanding: understanding,
      },
    });
  }
}

return output;

